example.query:
-- 1. Finding students who scored above their own city's average
SELECT s1.name, s1.city, s1.marks FROM Students AS s1
WHERE s1.marks > (SELECT AVG(s2.marks) FROM Students AS s2 WHERE s2.city = s1.city);

-- 2. Finding the highest scorer within each city using a correlated subquery
SELECT s1.name, s1.city, s1.marks FROM Students AS s1
WHERE s1.marks = (SELECT MAX(s2.marks) FROM Students AS s2 WHERE s2.city = s1.city);
